  'anqing/sail': ('안칭 항구', '안후이성의 양쯔강 항구인 안칭은 \'평화로운 축제\'라는 뜻을 담고 있어요.'),
  'ganzhou/orange': ('간난 네이블 오렌지', '중국에서 가장 달콤한 네이블 오렌지가 이곳의 붉은 토양에서 자라나요.'),
  'ganzhou/house': ('객가 토루', '객가 사람들은 수 세기 동안 독특한 원형 요새 주택인 토루에서 살아왔어요.'),
  'ganzhou/pavilion': ('위구정', '송나라 시인들이 노래했던 이 정자는 두 강이 만나는 지점을 내려다보고 있어요.'),
  'ganzhou/star': ('대장정', '중국 홍군의 대장정이 바로 이 도시에서 시작되었어요.'),
  'putian/shrine': ('마조묘', '뱃사람의 수호신인 마조 여신이 태어난 곳으로, 메이저우섬에 본당이 자리하고 있어요.'),
  'putian/lychee': ('리치 과수원', '천 년 된 리치 나무들이 가득해 이 도시는 \'리치의 고장\'이라는 별명을 얻었어요.'),
  'putian/shoe': ('신발의 도시', '전 세계 스포츠화의 상당 부분이 이곳의 공장에서 생산되고 있어요.'),
  'putian/wave': ('메이저우섬', '페리를 타고 들어갈 수 있는 이 섬은 아름다운 해변과 사원 축제로 유명해요.'),
  'mudanjiang/snow': ('중국 설향', '겨울이면 두꺼운 눈이 쌓여 동화 속 마을처럼 반짝이는 풍경을 자랑해요.'),
  'mudanjiang/lake': ('징포호', '화산 활동으로 만들어진 호수로, 겨울에도 댜오수이러우 폭포가 웅장하게 쏟아져요.'),
  'mudanjiang/tiger': ('시베리아 호랑이 공원', '세계에서 가장 큰 시베리아 호랑이 보호구역 중 하나예요.'),
  'mudanjiang/ski': ('스키 시즌', '눈이 길게 내리는 겨울 덕분에 스키어들에게 인기 있는 명소로 꼽혀요.'),
  'changzhou/dino': ('공룡원', '중국에서 가장 유명한 공룡 테마파크로, 가족 단위 여행객에게 인기가 많아요.'),
  'changzhou/pagoda': ('톈닝사 탑', '높이 153미터에 달하는 세계에서 가장 높은 탑이 도심 한가운데 솟아 있어요.'),
  'changzhou/comb': ('빗 공예', '천 년의 역사를 자랑하는 창저우의 빗은 과거에 궁중 진상품으로 쓰이기도 했어요.'),
  'changzhou/canal': ('대운하', '운하를 따라 걷다 보면 옛 거리의 정취와 화려한 야경을 즐길 수 있어요.'),
  'shaoxing/wine': ('사오싱주', '중국 요리에 빠지지 않는 유명한 황주가 수천 년 동안 이곳에서 빚어지고 있어요.'),
  'shaoxing/bridge': ('석교', '운하가 발달한 사오싱에는 수백 개의 아치형 돌다리가 그대로 보존되어 있어요.'),
  'shaoxing/pen': ('서예의 성지', '왕희지가 머물렀던 난팅은 서예를 공부하는 사람들에게 성지와 같은 곳이에요.'),
  'shaoxing/boat': ('우펑선', '발로 노를 저어 움직이는 검은 지붕의 우펑선은 운하를 즐기는 가장 고전적인 방법이에요.'),
  'bengbu/shell': ('진주의 항구', '지명 자체가 \'조개 부두\'라는 뜻으로, 과거 화이허강의 진주로 명성이 높았어요.'),
  'bengbu/train': ('철도 요충지', '남북을 잇는 철도 노선이 화이허를 건너는 곳으로, 벵부라는 도시는 이 역을 중심으로 성장했습니다.'),
  'bengbu/river': ('화이허', '중국의 남북을 가르는 기준이 되는 화이허가 바로 이곳을 흐릅니다.'),
  'bengbu/blossom': ('봄꽃 축제', '매년 봄이 되면 강변 공원마다 화사한 꽃들이 피어나 축제가 열립니다.'),
  'jiujiang/mountain': ('루산', '유네스코 세계유산으로 등재된 루산은 안개 낀 절경으로 수많은 시인과 화가들에게 영감을 주었습니다.'),
  'jiujiang/tea': ('윈우차', '루산의 비탈에서 재배되는 윈우차는 중국에서 가장 섬세한 맛을 자랑하는 차 중 하나입니다.'),
  'jiujiang/lake': ('포양호', '중국 최대의 담수호인 포양호는 겨울철이 되면 수천 마리의 학들이 찾아오는 철새 도래지입니다.'),
  'jiujiang/scroll': ('시의 도시', '백거이와 소동파 같은 대문호들이 이곳 강변에서 아름다운 시를 남겼습니다.'),
  'quanzhou/ship': ('해상 실크로드', '마르코 폴로가 \'자이툰\'이라 불렀던 이곳은 중세 시대 세계 최대의 항구였으며 유네스코 세계유산으로 지정되었습니다.'),
  'quanzhou/mosque': ('칭징사', '1009년에 세워진 이 돌로 만든 이슬람 사원은 중국에서 가장 오래된 사원 중 하나입니다.'),
  'quanzhou/puppet': ('꼭두각시 인형극', '취안저우의 줄 인형극은 천 년의 역사를 이어온 전통 공연 예술입니다.'),
  'quanzhou/tea': ('철관음', '인근 안시에서 생산되는 우롱차인 철관음은 세계적으로 유명한 명차입니다.'),
  'shanghai/pearl': ('동방명주', '황푸강 위로 솟아오른 분홍색 구체가 특징인 이 타워는 현대 상하이를 상징하는 랜드마크입니다.'),
  'shanghai/bund': ('와이탄', '강변을 따라 늘어선 고풍스러운 건축물들은 옛 상하이의 화려했던 시절을 보여줍니다.'),
  'shanghai/garden': ('예원', '명나라 시대에 조성된 정원으로, 도심 한가운데서 바위와 연못이 어우러진 고즈넉한 휴식을 즐길 수 있습니다.'),
  'shanghai/xlb': ('샤오룽바오', '뜨거운 육즙을 가득 머금은 찜 요리로, 상하이 아침 식사의 정수로 꼽힙니다.'),
  'hangzhou/lake': ('시후', '버드나무와 작은 섬, 아치형 다리가 어우러진 시후는 중국 시인들에게 가장 많은 찬사를 받은 호수예요.'),
  'hangzhou/tea': ('롱징차', '호수 주변 비탈에서 재배되는 \'용정차\'는 중국에서 가장 유명한 녹차로 손꼽혀요.'),
  'hangzhou/temple': ('링인사', '1,700년의 역사를 자랑하는 링인사는 정교한 암벽 조각과 거대한 불상으로 유명한 사찰이에요.'),
  'hangzhou/silk': ('실크 시티', '천 년의 역사를 지닌 항저우 비단은 실크로드 동쪽 끝에서 부를 상징하던 귀한 특산품이에요.'),
  'chongqing/hongya': ('훙야둥', '절벽을 따라 세워진 훙야둥은 밤이 되면 강 위로 동화 속 풍경처럼 화려한 야경을 뽐내요.'),
  'chongqing/hotpot': ('충칭 훠궈', '얼얼한 산초와 매운 기름이 끓어오르는 훠궈는 산악 도시 충칭의 뜨거운 영혼과도 같아요.'),
  'chongqing/monorail': ('충칭 모노레일', '건물 사이를 관통하며 달리는 모노레일은 언덕 위에 세워진 충칭의 상징적인 풍경이에요.'),
  'chongqing/river': ('양쯔강 싼샤', '두 강이 만나는 지점에 위치한 충칭 항구에서는 양쯔강의 절경을 감상하는 싼샤 유람선이 출발해요.'),
  'dalian/square': ('싱하이 광장', '아시아에서 가장 큰 도시 광장인 싱하이 광장은 바닷가를 따라 다양한 축제와 공연으로 가득 차요.'),
  'dalian/beach': ('다롄 해변', '바위가 어우러진 해안과 시원한 여름 날씨 덕분에 다롄은 중국 북부에서 가장 사랑받는 휴양지예요.'),
  'dalian/football': ('축구의 도시', '중국 축구의 요람이라 불리는 다롄은 명문 구단들이 탄생한 축구의 본고장이에요.'),
  'dalian/seafood': ('다롄 해산물', '황해의 차가운 바다에서 건져 올린 가리비, 새우, 성게는 다롄 식탁을 더욱 풍성하게 만들어 줘요.'),
  'shenyang/palace': ('선양 고궁', '청나라의 첫 번째 궁궐인 선양 고궁은 베이징 자금성의 축소판 같은 매력을 지니고 있어요.'),
  'shenyang/tomb': ('청나라 황릉', '도시를 둘러싸고 있는 동릉과 북릉은 청나라를 세운 황제들의 웅장한 무덤이에요.'),
  'shenyang/factory': ('산업의 요람', '중국 중공업의 발상지인 선양은 거대한 공장들이 밀집해 있어 \'동양의 루르\'라고도 불려요.'),
  'shenyang/dumpling': ('라오볜 만두', '200년 전통을 자랑하는 라오볜 만두는 북방 요리를 대표하는 별미예요.'),
  'hefei/judge': ('포공사', '정의로운 판관 포청천의 고향인 이곳의 사당은 청렴한 정신을 기리는 장소예요.'),
  'hefei/science': ('과학 도시', '중국을 대표하는 유수의 대학과 연구소가 밀집해 있는 첨단 기술의 중심지예요.'),
  'hefei/lake': ('차오후', '중국 5대 담수호 중 하나로, 맛 좋은 백어와 게가 나기로 유명해요.'),
  'hefei/cake': ('루저우 참깨떡', '달콤한 소가 들어간 참깨떡은 옛 루저우 지역에서 오랫동안 사랑받아 온 간식이에요.'),
  'foshan/wingchun': ('영춘권', '엽문과 이소룡의 무술 뿌리인 영춘권의 본고장이에요.'),
  'foshan/lion': ('사자춤', '남부 사자춤의 수도라 불리며, 화려한 사자들이 기둥 위를 넘나드는 모습이 장관이에요.'),
  'foshan/ceramic': ('스완 도자기', '천 년의 역사를 지닌 가마에서 생동감 넘치는 스완 도자기 인형들이 지금도 만들어지고 있어요.'),
  'foshan/opera': ('광둥 오페라', '중국 남부에서 가장 사랑받는 무대 예술인 광둥 오페라가 이곳에서 꽃피웠어요.'),
  'guiyang/pavilion': ('자슈거', '난밍강 위에 자리한 3층 높이의 자슈거는 400년 동안 귀양을 상징해 온 건축물이에요.'),
  'guiyang/sourfish': ('쏸탕위', '발효 토마토를 넣어 새콤하게 끓여낸 생선 요리인 쏸탕위는 구이저우를 대표하는 음식이에요.'),
  'guiyang/waterfall': ('황궈수 폭포', '아시아 최대 규모를 자랑하는 황궈수 폭포는 거대한 물줄기와 함께 아름다운 무지개를 만들어내요.'),
  'guiyang/miao': ('먀오족 문화', '은장식을 머리에 쓴 먀오족의 화려한 축제와 자수는 산간 마을을 더욱 빛나게 해요.'),
  'changchun/film': ('영화 도시', '중국 영화의 발상지이자 \'동양의 할리우드\'라 불리는 영화 촬영소가 이곳에 있어요.'),
  'changchun/car': ('자동차 도시', '중국 최초의 국산 자동차가 탄생한 곳으로, 명실상부한 중국 자동차 산업의 중심지예요.'),
  'changchun/palace': ('위만황궁', '마지막 황제가 머물렀던 이 궁궐은 격동의 역사를 고스란히 간직하고 있어요.'),
  'changchun/snow': ('겨울 눈', '길고 하얀 겨울이 찾아오면 도시는 얼음 조각과 스키장으로 반짝여요.'),
  'xining/lake': ('칭하이호', '중국 최대의 염호로, 여름이면 호수 주변을 가득 채우는 노란 유채꽃밭으로 유명해요.'),
  'xining/monastery': ('타얼쓰', '티베트 불교 6대 사원 중 하나로, 야크 버터로 만든 정교한 조각품이 특히 잘 알려져 있어요.'),
  'xining/flower': ('유채꽃', '7월이 되면 고원 지대는 지평선 끝까지 황금빛 유채꽃으로 뒤덮여요.'),
  'xining/lamb': ('야크와 양고기', '후이족과 티베트족의 손맛이 담긴 수타면과 양꼬치는 고원 지대를 대표하는 별미예요.'),
  'guilin/karst': ('리강 카르스트', '안개 속으로 솟아오른 석회암 봉우리들은 20위안 지폐 뒷면의 배경이기도 해요.'),
  'guilin/elephant': ('샹비산', '강물에 코를 담그고 있는 코끼리 모양의 바위는 구이린을 상징하는 명물이에요.'),
  'guilin/terrace': ('룽지 다랑논', '용의 등뼈를 닮은 이 다랑논은 수 세기 동안 이어진 사람들의 땀방울이 빚어낸 계단식 논이에요.'),
  'guilin/osmanthus': ('계화꽃', '도시 이름에 \'계수나무 숲\'이라는 뜻이 담겨 있듯, 가을이면 도시 전체가 달콤한 꽃향기로 가득 차요.'),
  'wenzhou/merchant': ('원저우 상인 정신', '\'중국의 유대인\'이라 불리는 원저우 기업가들은 전 세계에 걸쳐 거대한 비즈니스 네트워크를 구축하고 있어요.'),
  'wenzhou/shoe': ('신발과 가죽', '전 세계 가죽 신발의 상당수가 바로 이 공업 도시인 원저우에서 생산돼요.'),
  'wenzhou/mountain': ('옌당산', '폭포와 험준한 봉우리로 유명하며, \'바다 위의 제일가는 명산\'으로 칭송받아요.'),
  'wenzhou/seafood': ('해산물', '동중국해에서 갓 잡아 올린 오징어, 가리비, 생선은 이곳 식탁에서 빠질 수 없는 주재료예요.'),
  'tangshan/memorial': ('지진 기념비', '1976년 대지진을 기리는 이 기념 공원은 다시 일어선 도시의 상징과도 같아요.'),
  'tangshan/coal': ('탕산 탄광', '중국 최초의 근대식 탄광과 철도가 시작된 이곳은 중국 산업의 발상지입니다.'),
  'tangshan/ceramic': ('탕산 도자기', '북방의 도자기 도시로 불리는 탕산의 본차이나는 우아한 품질로 유명합니다.'),
  'tangshan/lake': ('난후 공원', '과거 탄광 채굴장이었던 곳을 공원으로 탈바꿈시켜 도시의 녹색 허파 역할을 하고 있습니다.'),
  'anshan/steel': ('안산 철강', '중국 최대 규모의 제철소가 세워진 이곳은 명실상부한 중국의 철강 수도입니다.'),
  'anshan/jade': ('슈옌 옥', '세계 최대 규모의 옥 조각품이 있는 이곳은 중국을 대표하는 옥의 고장입니다.'),
  'anshan/mountain': ('첸산', '천 개의 연꽃 봉우리가 솟아 있다는 첸산은 사찰과 기암괴석이 어우러진 북방의 명산입니다.'),
  'anshan/spring': ('탕강쯔 온천', '천 년의 역사를 자랑하는 이곳은 과거 황제들도 즐겨 찾았던 치유의 온천입니다.'),
  'linyi/market': ('린이 도매시장', '중국 북부 최대 규모의 도매 허브로, 이곳의 물건들은 전국 각지로 유통됩니다.'),
  'linyi/brush': ('왕희지 고향', '서예의 성인으로 불리는 왕희지가 태어난 곳으로, 서예와 붓의 고장으로 유명합니다.'),
  'linyi/mountain': ('멍산', '산둥성에서 두 번째로 높은 산으로, 맑은 공기와 폭포가 어우러진 천연 산소 카페입니다.'),
  'linyi/pancake': ('이멍 지엔빙', '옥수수로 얇게 부쳐낸 지엔빙은 이멍 산간 지역 사람들의 오랜 주식입니다.'),
  'cangzhou/lion': ('창저우 철사자', '1,100년의 역사를 간직한 거대한 철제 사자상은 창저우를 상징하는 자랑스러운 문화재입니다.'),
  'cangzhou/martial': ('창저우 무술', '중국 무술의 고향으로 불리며, 수많은 무술 대가와 문파가 이곳에서 배출되었습니다.'),
  'cangzhou/canal': ('징항 대운하', '베이징과 항저우를 잇는 대운하가 도시를 가로지르며, 옛 부두의 정취가 그대로 남아 있습니다.'),
  'cangzhou/jujube': ('금사 대추', '껍질이 얇고 달콤한 금사 대추는 건과일의 왕으로 불릴 만큼 맛이 뛰어납니다.'),
  'nantong/textile': ('난퉁 방직성', '중국 가정용 섬유의 중심지로, 이곳에서 생산된 면직물은 전 세계로 수출되고 있어요.'),
  'nantong/mountain': ('랑산', '양쯔강 하구에 솟아 있는 다섯 개의 봉우리로 이루어진 성스러운 산으로, 순례객과 관광객의 발길이 끊이지 않아요.'),
  'nantong/kite': ('반야오 연', '연에 피리를 달아 바람이 불면 소리가 나는 \'반야오\'는 난퉁의 오랜 전통 공예품이에요.'),
  'nantong/school': ('근대 교육의 발상지', '산업가 장젠이 이곳에 중국 최초의 근대식 학교와 박물관을 세웠어요.'),
  'taizhou/opera': ('메이란팡', '경극의 전설적인 거장 메이란팡이 태어난 고향이에요.'),
  'taizhou/tea': ('자오차', '아침에 찐빵과 차를 곁들여 먹는 \'자오차\'는 타이저우 사람들의 일상적인 아침 식사 문화예요.'),
  'taizhou/boat': ('친퉁 보트 축제', '봄이 되면 수백 명의 노잡이가 참여하는 보트 경주가 열려 강 위를 활기차게 만들어요.'),
  'taizhou/meatball': ('사자두', '크고 부드러운 돼지고기 완자인 \'사자두\'는 화이양 요리의 대표적인 메뉴예요.'),
  'jinhua/ham': ('진화 햄', '수백 년 전통의 방식으로 염장한 붉은빛의 진화 햄은 중국에서 가장 유명한 햄이에요.'),
  'jinhua/film': ('헝뎬 월드 스튜디오', '세계 최대 규모의 야외 촬영장으로, 수많은 시대극이 이곳에서 제작되고 있어요.'),
  'jinhua/cave': ('솽룽 동굴', '낮은 바위 문을 지나 배를 타고 들어가는 신비로운 지하 동굴의 풍경이 정말 아름다워요.'),
  'jinhua/bridge': ('고대 석교', '아치형 돌다리와 물길이 어우러진 마을에서 강남 지역 특유의 우아함을 느낄 수 있어요.'),
  'wuhu/park': ('팡터 원더랜드', '중국 최대 규모의 테마파크 중 하나로, 가족 단위 방문객들에게 즐거운 추억을 선사해요.'),
  'wuhu/ironart': ('철화', '연철을 두드려 만든 우아한 \'철화\'는 300년 역사를 자랑하는 전통 공예예요.'),
  'wuhu/rice': ('쌀의 도시', '양쯔강변에 위치한 우후는 역사적으로 중국 최대의 쌀 시장이었던 곳이에요.'),
  'wuhu/river': ('양쯔강 항구', '분주한 강 항구가 있어 안후이성의 바닷길 관문 역할을 하는 도시예요.'),
  'huangshan/peak': ('황산', '화강암 봉우리와 운해, 기이한 소나무가 어우러진 중국에서 가장 유명한 산이에요.'),
  'huangshan/village': ('훙춘 마을', '물길과 하얀 벽이 어우러진 휘주 양식의 마을로, 유네스코 세계문화유산에 등재된 그림 같은 곳이에요.'),
  'huangshan/tea': ('황산모봉', '안개 낀 비탈에서 자란 솜털 덮인 찻잎으로 만든 녹차로, 중국 10대 명차 중 하나예요.'),
  'huangshan/ink': ('휘묵과 예술', '휘주 지역의 먹과 목조 가옥, 서예는 이 지역을 대표하는 문화적 보물이에요.'),
  'yichun/moon': ('밍웨산', '밝은 달이라는 뜻의 밍웨산은 온천과 케이블카에서 내려다보는 풍경으로 유명해요.'),
  'yichun/spring': ('온천', '희귀한 셀레늄이 풍부한 온천 덕분에 중국의 대표적인 온천 휴양지로 자리 잡았어요.'),
  'yichun/zen': ('선불교', '중국 선불교의 뿌리가 깊은 산속 사찰들은 마음의 평온을 찾게 해 줘요.'),
  'yichun/rice': ('곡창지대', '비옥한 위안허 평야는 예로부터 장시성의 곡창지대 역할을 해왔어요.'),
  'zhangzhou/narcissus': ('수선화', '중국에서 가장 유명한 수선화 구근이 자라는 곳으로, 봄 축제를 상징하는 꽃이에요.'),
  'zhangzhou/tulou': ('객가 토루', '거대한 원형의 흙집 요새로, 유네스코 세계문화유산이며 한 지붕 아래 마을 사람들이 모여 살아요.'),
  'zhangzhou/banana': ('열대 과일', '바나나, 용안, 귤 과수원 덕분에 따뜻한 삼각주 지역은 일 년 내내 푸르러요.'),
  'zhangzhou/coast': ('둥산섬', '황금빛 해변과 어촌 마을이 어우러진 이곳은 남부 해안의 진주라 불려요.'),
  'guangzhou/tower': ('광저우 타워', '샤오만야오라고도 불리는 이 가느다란 타워는 세계에서 가장 높은 타워 중 하나로, 밤마다 화려한 빛을 뽐내요.'),
  'guangzhou/dimsum': ('얌차', '대나무 찜기에 찐 딤섬을 차와 함께 즐기는 얌차는 광둥 식문화의 핵심이에요.'),
  'guangzhou/academy': ('천씨서원', '정교한 목조각과 도자기 장식으로 유명한 이곳은 광둥 건축 예술의 걸작으로 꼽혀요.'),
  'guangzhou/flower': ('꽃의 도시', '일 년 내내 꽃이 피는 광저우는 매년 새해마다 대규모 꽃 시장이 열려 \'꽃의 도시\'라고 불려요.'),
  'wuhan/crane': ('황학루', '양쯔강을 굽어보는 천 년 역사의 이 누각은 중국의 수많은 명시를 탄생시킨 영감의 원천이에요.'),
  'wuhan/noodle': ('러간몐', '고소한 참깨 소스를 듬뿍 얹은 러간몐은 우한 사람들에게 없어서는 안 될 아침 식사 메뉴예요.'),
  'wuhan/duckneck': ('야보즈', '매콤하게 졸여낸 오리 목 요리인 야보즈는 우한 사람들이 야식으로 즐겨 찾는 대표 간식이에요.'),
  'wuhan/university': ('우한대학교 벚꽃', '봄이 되면 우한대학교 캠퍼스를 가득 채우는 아름다운 벚꽃을 보기 위해 수많은 방문객이 모여들어요.'),
  'tianjin/eye': ('톈진 아이', '다리 위에 세워진 거대한 관람차로, 정상에 오르면 강변의 풍경을 한눈에 내려다볼 수 있어요.'),
  'tianjin/baozi': ('거우부리 만두', '주름을 정교하게 잡은 돼지고기 찜만두인 거우부리는 150년 전통을 자랑하는 톈진의 명물이에요.'),
  'tianjin/crosstalk': ('샹성', '두 사람이 주고받는 만담 형식의 샹성은 톈진의 찻집 문화에서 시작된 전통 공연 예술이에요.'),
  'tianjin/architecture': ('우다다오', '유럽풍 저택이 모여 있는 우다다오는 \'건축 박물관\'이라 불릴 만큼 이국적인 풍경을 자랑해요.'),
  'xiamen/island': ('구랑위', '차 없는 거리와 고풍스러운 서양식 저택이 어우러진 구랑위는 유네스코 세계문화유산으로 지정된 섬이에요.'),
  'xiamen/piano': ('피아노의 섬', '인구 대비 피아노 보유율이 가장 높은 구랑위는 \'피아노의 섬\'이라는 별칭으로 유명해요.'),
  'xiamen/egret': ('백로', '샤먼의 상징인 백로는 예부터 이 도시를 \'백로의 섬\'이라 불렀던 것에서 유래했어요.'),
  'xiamen/oyster': ('굴전', '신선한 굴과 달걀을 넣어 바삭하게 부쳐낸 굴전은 샤먼 해안 지역의 대표적인 별미예요.'),
  'harbin/ice': ('하얼빈 빙등제', '겨울마다 거대한 얼음 궁전과 화려한 조명이 어우러지는 이곳의 축제는 세계 최대 규모를 자랑해요.'),
  'harbin/cathedral': ('성 소피아 성당', '양파 모양의 돔이 특징인 이 러시아 정교회 성당은 하얼빈의 유럽풍 역사를 상징하는 랜드마크예요.'),
  'harbin/sausage': ('홍창(하얼빈 소시지)', '러시아식으로 훈연한 붉은색 소시지는 하얼빈에서 백 년 넘게 사랑받아 온 별미예요.'),
  'harbin/accordion': ('음악의 도시', '러시아 문화의 영향을 깊게 받은 하얼빈은 중국 최초의 교향악단이 탄생한 음악의 도시예요.'),
  'fuzhou/alley': ('싼팡치샹', '흰 벽과 검은 기와가 어우러진 이 옛 거리는 명·청 시대 건축 양식을 그대로 간직한 살아있는 박물관이에요.'),
  'fuzhou/banyan': ('용의 도시', '거리마다 거대한 고목들이 그늘을 드리우고 있어 푸저우는 \'용의 도시\'라고도 불려요.'),
  'fuzhou/hotspring': ('온천', '도심 곳곳에서 솟아나는 온천수는 천 년 넘게 푸저우 시민들의 목욕 문화가 되어왔어요.'),
  'fuzhou/soup': ('불도장', '수십 가지 진귀한 재료를 푹 고아 만든 이 고급 요리는 푸젠 요리의 정수로 꼽혀요.'),
  'dongguan/robot': ('세계의 공장', '자동화된 공장들이 밀집한 둥관은 전 세계 전자 제품의 상당 부분을 생산하고 있어요.'),
  'dongguan/basketball': ('농구의 도시', '중국에서 가장 화려한 수상 경력을 자랑하는 농구 클럽이 바로 이 \'농구의 도시\' 둥관을 연고로 하고 있어요.'),
  'dongguan/keyuan': ('커위안', '연못과 정자가 아름답기로 유명한 이곳은 광둥성의 4대 명원 중 하나예요.'),
  'dongguan/cannon': ('후먼 포대', '아편 전쟁의 시발점이 된 후먼 포대는 당시 아편을 불태웠던 역사의 현장이에요.'),
  'lanzhou/beefnoodle': ('란저우 우육면', '맑은 소고기 육수와 직접 뽑은 면발을 자랑하는 란저우는 중국 면 요리의 본고장이에요.'),
  'lanzhou/waterwheel': ('수차', '황허 강변의 거대한 수차는 수백 년 전부터 이어져 온 관개 기술의 역사를 상징해요.'),
  'lanzhou/statue': ('황허 어머니상', '강변에 세워진 어머니와 아이의 동상은 중국 문명을 길러낸 황허강의 의미를 담고 있어요.'),
  'lanzhou/raft': ('양가죽 뗏목', '양가죽을 부풀려 만든 전통 뗏목은 지금도 황허강 위를 유유히 떠다니고 있어요.'),
  'urumqi/bazaar': ('국제대바자', '이슬람 양식의 첨탑과 향신료 가게들이 어우러져 실크로드의 이국적인 정취를 물씬 풍깁니다.'),
  'urumqi/tianshan': ('천지', '천산의 만년설 아래 자리 잡은 천지는 울창한 가문비나무 숲으로 둘러싸여 아름다운 풍경을 자랑합니다.'),
  'urumqi/kebab': ('양꼬치', '향신료를 뿌려 숯불에 구운 양꼬치는 위구르 식탁에서 빠질 수 없는 대표적인 음식입니다.'),
  'urumqi/dance': ('위구르 전통춤', '북과 라와프 연주에 맞춰 빙글빙글 도는 위구르 전통춤은 축제 분위기를 한층 더 밝게 만들어 줍니다.'),
  'haikou/coconut': ('코코넛 시티', '거리마다 코코넛 나무가 줄지어 서 있어 하이커우는 \'코코넛의 도시\'라는 별명을 얻었습니다.'),
  'haikou/arcade': ('치러우 건축군', '남방 특유의 기둥식 건축 양식인 \'치러우\'가 늘어선 거리는 그늘진 산책로를 형성합니다.'),
  'haikou/crater': ('화산 공원', '도시 외곽에는 사화산 분화구가 푸른 녹지로 변모한 지질 공원이 조성되어 있습니다.'),
  'haikou/turtle': ('열대 바다', '따뜻하고 맑은 바닷물과 산호초가 어우러진 이곳은 바다거북의 소중한 서식지입니다.'),
  'luoyang/grotto': ('룽먼 석굴', '절벽에 새겨진 수만 개의 불상은 유네스코 세계문화유산으로 지정된 예술적 보물입니다.'),
  'luoyang/peony': ('모란의 도시', '매년 4월이면 수천 송이의 모란이 만개하여 뤄양을 \'모란의 도시\'로 물들입니다.'),
  'luoyang/whitehorse': ('백마사', '서기 68년에 세워진 백마사는 중국 최초의 불교 사원으로 알려져 있습니다.'),
  'luoyang/capital': ('고도 뤄양', '13개 왕조의 수도였던 뤄양은 중국 문명의 발상지 중 하나입니다.'),
  'shantou/gongfutea': ('쿵푸차', '작은 찻잔에 정성스럽게 우려내는 차오산 쿵푸차는 환대의 미학을 담고 있습니다.'),
  'shantou/beefpot': ('소고기 훠궈', '신선한 소고기를 얇게 썰어 살짝 데쳐 먹는 차오산식 훠궈는 매우 유명합니다.'),
  'shantou/opera': ('차오쥐', '600년의 역사를 지닌 차오쥐는 섬세한 노래와 화려한 자수 의상으로 잘 알려져 있습니다.'),
  'shantou/harbor': ('산터우항', '수많은 화교의 고향인 이곳은 예로부터 해상 무역의 관문 역할을 해온 항구 도시예요.'),
  'baoding/mansion': ('직례총독부', '청나라 시대 최고 지방 관청이었던 이곳은 당시의 행정 시설이 아주 잘 보존되어 있어요.'),
  'baoding/donkeyburger': ('뤼러우훠사오', '바삭한 빵 사이에 양념한 당나귀 고기를 채워 넣은 이 지역의 대표적인 길거리 음식이에요.'),
  'baoding/balls': ('바오딩 철구', '손바닥 안에서 굴리며 손 운동을 하는 이 금속 공은 수백 년 동안 이어져 온 전통 건강법이에요.'),
  'baoding/reeds': ('바이양뎬', '중국 북부 최대의 습지인 이곳은 갈대와 연꽃이 가득해 새들의 낙원으로 불려요.'),
  'jilin/rime': ('지린 무송', '쑹화강변 나무에 하얗게 맺힌 상고대는 중국의 4대 자연 경관 중 하나로 꼽혀요.'),
  'jilin/snowboard': ('지린 스키장', '눈이 깊고 스키 시즌이 길어 중국 북부에서 손꼽히는 스키 명소예요.'),
  'jilin/meteorite': ('지린 운석 박물관', '1976년에 떨어진 세계 최대 규모의 석질 운석이 이곳에 전시되어 있어요.'),
  'jilin/skate': ('쑹화강 빙상장', '겨울이 되면 꽁꽁 언 쑹화강은 스케이트를 타거나 산책을 즐기는 사람들로 활기가 넘쳐요.'),
  'ordos/khan': ('칭기즈칸 능', '초원의 영웅 칭기즈칸을 기리는 웅장한 능묘로, 몽골 문화의 중심지예요.'),
  'ordos/cashmere': ('오르도스 캐시미어', '오르도스 산 염소 털로 만든 캐시미어는 세계 섬유 시장에서 높은 품질을 인정받고 있어요.'),
  'ordos/sanddune': ('샹사완', '모래 언덕을 타고 내려갈 때 소리가 나는 이곳은 쿠부치 사막에서 가장 인기 있는 여행지예요.'),
  'ordos/yurt': ('몽골식 게르', '끝없이 펼쳐진 초원 위에 세워진 하얀 펠트 천막인 게르는 유목민의 삶을 상징해요.'),
  'jining/confucius': ('공묘', '인근 취푸에 위치한 공자의 사당과 저택, 묘지는 유네스코 세계문화유산으로 지정되어 있어요.'),
  'jining/barge': ('징항 대운하', '베이징과 항저우를 잇는 운하의 주요 항구였던 지닝은 운하 문화의 중심지였어요.'),
  'jining/sword': ('량산 호걸', '고전 소설 \'수호지\'에 등장하는 108명의 호걸들이 이 습지 언덕에 모여들었어요.'),
  'jining/fishnet': ('웨이산호', '중국 북부에서 가장 큰 연꽃 호수인 이곳에서는 어부들이 전통적인 방식으로 그물을 던져요.'),
  'langfang/culture': ('실크로드 문화센터', '도시의 거대한 현대식 문화 센터에서 실크로드의 다양한 예술을 한자리에서 만나볼 수 있어요.'),
  'langfang/furniture': ('가구 도시', '인근의 샹허는 중국에서 가장 큰 가구 제조 및 유통 허브 중 하나예요.'),
  'langfang/tunnel': ('고대 전쟁 터널', '천 년의 역사를 간직한 지하 군사 터널은 과거 국경 방어의 흔적을 보여줘요.'),
  'langfang/themepark': ('제1성 테마파크', '고대 성곽 도시를 재현한 거대한 테마파크로 가족 단위 여행객에게 인기가 많아요.'),
  'yancheng/salt': ('염성', '이름 그대로 \'소금의 성\'을 뜻하는 옌청은 수 세기 동안 중국 소금 생산의 중심지였어요.'),
  'yancheng/crane': ('단정학', '이 해안 습지는 야생 단정학이 겨울을 나는 세계 최대 규모의 서식지예요.'),
  'yancheng/elk': ('다비드사슴', '한때 야생에서 멸종되었던 다비드사슴이 이곳 습지에서 다시 번식하며 생명을 이어가고 있어요.'),
  'yancheng/wetland': ('해안 습지', '유네스코 세계자연유산으로 등재된 이곳의 갯벌은 철새들의 중요한 중간 기착지예요.'),
  'huzhou/brush': ('후저우 붓', '중국 서예의 \'문방사우\' 중 하나인 후저우 붓이 바로 이곳에서 만들어져요.'),
  'huzhou/bamboo': ('안지 대나무 숲', '영화 촬영지로도 유명한 끝없이 펼쳐진 푸른 대나무 숲이 시원한 공기를 선사해요.'),
  'huzhou/silkworm': ('누에', '타이후 호수의 남쪽 기슭은 천 년 동안 이어져 온 뽕나무 비단 생산의 중심지예요.'),
  'huzhou/whitetea': ('안지 백차', '연한 잎과 달콤한 맛이 특징인 안지 백차는 중국에서 가장 귀한 차 중 하나예요.'),
  'quzhou/go': ('바둑', '란커산 전설이 깃든 이 도시는 바둑의 성지로 널리 알려져 있어요.'),
  'quzhou/peaks': ('장랑산', '하늘을 찌를 듯 솟아 있는 세 개의 거대한 돌기둥이 유네스코 세계유산으로 지정된 독특한 풍경을 자아내요.'),
  'quzhou/ponkan': ('취저우 폰칸(만다린)', '껍질이 달콤한 폰칸 귤은 온화한 언덕에서 자라나 겨울철에 맛볼 수 있는 귀한 선물이에요.'),
  'quzhou/cake': ('샤오빙(구운 납작빵)', '화덕 벽에 붙여 바삭하게 구워낸 참깨 납작빵은 이곳의 대표적인 아침 식사 메뉴예요.'),
  'huainan/tofu': ('두부의 발상지', '2,000년 전 팔공산에서 처음 만들어진 두부는 이곳에서 시작되어 전 세계의 요리로 퍼져나갔어요.'),
  'huainan/coalmine': ('석탄 도시', '풍부한 석탄층을 보유한 화이난은 중국 동부 지역의 주요 에너지 공급 기지예요.'),
  'huainan/oldtown': ('서우현 고성', '송나라 시대의 성벽이 온전히 보존되어 있어 고대 방어 시설의 형태를 잘 보여주는 귀중한 유적이에요.'),
  'huainan/classic': ('회남자', '유안 왕이 편찬한 철학 고전인 \'회남자\'가 바로 이 땅에서 집필되었어요.'),
  'jingdezhen/porcelain': ('도자기의 수도', '천 년 동안 황실 도자기를 생산해 온 이곳은 세계적으로 \'도자기의 수도\'라 불려요.'),
  'jingdezhen/kiln': ('고가마', '나무를 때어 불을 지피는 용 모양의 가마는 전통 도자기 제작 방식을 오늘날까지 이어오고 있어요.'),
  'jingdezhen/bluewhite': ('청화백자', '흰 바탕에 코발트색 안료로 그림을 그려 넣은 청화백자는 이 도시를 상징하는 세계적인 명품이에요.'),
  'jingdezhen/painting': ('도자기 회화', '장인들이 섬세한 붓으로 도자기에 그려 넣은 그림은 마치 훌륭한 예술 작품처럼 높은 가치를 인정받아요.'),
  'jian/jinggang': ('징강산', '안개 자욱한 이 산은 혁명의 첫 거점이자 중국 \'홍색 관광\'의 중심지예요.'),
  'jian/torch': ('혁명의 불꽃', '\'작은 불꽃이 들판을 태운다\'는 말의 유래가 된 이곳은 역사적인 기념지예요.'),
  'jian/academy': ('바이루저우 서원', '간강의 섬 위에 세워진 천 년 역사의 서원은 수많은 과거 급제자를 배출한 교육의 장이었어요.'),
  'jian/pine': ('징강산 소나무', '안개를 뚫고 솟아오른 붉은 소나무는 산의 정신과 끈기를 상징해요.'),
  'nanping/wuyi': ('우이산', '붉은 절벽과 푸른 계곡이 어우러진 유네스코 세계유산으로, 자연과 문화의 보고라 불려요.'),
  'nanping/rocktea': ('암차', '절벽 바위틈에서 자란 우롱차인 \'대홍포\'는 세계에서 가장 비싼 차 중 하나로 손꼽혀요.'),
  'nanping/bambooraft': ('구곡계 뗏목', '붉은 절벽 사이로 흐르는 구곡계에서 대나무 뗏목을 타고 유유자적하게 풍경을 감상할 수 있어요.'),
  'nanping/scholar': ('주희', '성리학을 집대성한 주희가 바로 이 우이산 자락에서 제자들을 가르치며 학문을 닦았어요.'),
  'beijing/great-wall': ('만리장성', '중국 북부 국경을 지키기 위해 수세기에 걸쳐 쌓은 세계에서 가장 긴 성벽으로, 베이징 인근의 팔달령 구간이 가장 유명해요.'),
  'beijing/temple': ('천단공원', '명·청 시대 황제가 풍년을 기원하며 제사를 지내던 곳으로, 못을 하나도 쓰지 않고 지은 푸른 지붕의 건축물이 매우 인상적이에요.'),
  'beijing/pagoda': ('천녕사 탑', '요나라 시대에 세워진 13층 벽돌 탑으로, 베이징에서 가장 오래된 건축물 중 하나이자 천 년의 역사를 간직하고 있어요.'),
  'beijing/opera': ('경극', '노래와 대사, 무술과 곡예가 어우러진 중국의 전통 예술로, 배우들의 얼굴에 그려진 화장인 \'연보\'를 통해 인물의 성격을 알 수 있어요.'),
};
